    21→	Authenticate(ctx context.Context) (context.Context, error)
    22→}
    23→
    24→type AuthenticatorFunc func(context.Context) (context.Context, error)
    25→
    26→func (fn AuthenticatorFunc) Authenticate(ctx context.Context) (context.Context, error) {
    27→	return fn(ctx)
    28→}
    29→
    30→// authenticator can authenticate GRPC requests.
    31→type authenticator struct {
    32→	contextHandler grpccontext.ContextHandler
    33→	logger         log.Logger
    34→
    35→	APIKeyService        apikey.Service
    36→	UserService          user.Service
    37→	AccessControlService accesscontrol.Service
    38→}
    39→
    40→func ProvideAuthenticator(apiKeyService apikey.Service, userService user.Service, accessControlService accesscontrol.Service, contextHandler grpccontext.ContextHandler) Authenticator {
    41→	return &authenticator{
    42→		contextHandler: contextHandler,
    43→		logger:         log.New("grpc-server-authenticator"),
    44→
    45→		AccessControlService: accessControlService,
    46→		APIKeyService:        apiKeyService,
    47→		UserService:          userService,
    48→	}
    49→}
